    function printcontent(content){
        
        var mywindow = window.open('', '', '');
        mywindow.document.write('<html><title>fobrain | Best Rated School Management System</title>');
        mywindow.document.write('<link href="https://www.fobrain.com/wiz-design/assets/css/fobrain-style.css" rel="stylesheet">');
        mywindow.document.write('<body>');
        mywindow.document.write(content);
        mywindow.document.write('</body></html>');
        mywindow.document.close();
        //mywindow.print();
        return true;
    }
    
    $('body').on('click','.plusMinus',function(event){  /* increase or decrease a page */
    
        event.stopImmediatePropagation();	
                                
        var $speech = $('#fobrain-page-div');
        var currentSize = $speech.css('fontSize');
        var num = parseFloat( currentSize, 10 );
        var unit = currentSize.slice(-2);
            if (this.id == 'plusIcon') {
                num *= 1.1;
            } else if (this.id == 'minusIcon') {
                num /= 1.1;
            }
                $speech.css('fontSize', num + unit);

            return false;
    });

    function showPageLoader(){  /* show loading image */

        $('#preload-wrapper').fadeIn(100); 

    } 

    function hidePageLoader(){  /* hide loading image */

        $('#preload-wrapper').fadeOut(2000);
        
    };	

    function responsivePage(){

        windowWidth = $(window).width();
        if (windowWidth < 992){ 				 
            $("body").toggleClass("sidebar-enable");  
        }else{
            document.body.setAttribute('data-sidebar-size', 'lg');
        }	

    }

